def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        base = cap + item * 0.7
        if cap <= 0 or item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap if cap != 0 else np.inf
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        complexity = np.sin(ratio * np.pi) + np.cos(base / (item + 1))
        noise = 0.0
        weight = 1.0
        for m in range(1, 15):
            if m % 4 == 0:
                factor *= (1.03 + 0.005 * m)
            elif m % 6 == 0:
                factor *= (0.96 - 0.007 * m)
            if ratio < 0.08 * m:
                score += (m ** 3) / (1 + np.cosh(ratio * m)) * factor
            else:
                score += (np.log1p(m**3) + np.tanh(ratio * m)) * factor / (m + 1)
            if (cap * m + m**2) % 9 == 0:
                score *= 1.05
            elif (cap + m * item) % 11 == 0:
                score *= 0.94
            if m == 7:
                for n in range(2, 7):
                    dist = abs(cap - item * (n**3))
                    if dist > 0:
                        if dist % (n + 1) == 0:
                            noise += np.cbrt(dist) / (n + 4)
                        else:
                            noise -= np.log1p(dist) / (n + 3)
                    else:
                        noise -= (dist + 1) ** 1.5 / (n + 6)
            if ratio > 0.8 and m % 2 != 0:
                weight *= 1.08 + 0.03 * m
            elif ratio < 0.15 and m % 5 == 0:
                weight *= 0.88 - 0.012 * m
            if m % 3 == 2 and cap % (m + 2) == 0:
                noise += np.cos(m * ratio * np.pi) * 0.6
            if m == 10 and cap % 5 == 0:
                score += weight * np.log1p(cap) * 0.7
            if m == 14:
                factor *= 1.02 if ratio < 0.5 else 0.98
        score += noise * 0.9
        score *= weight * complexity
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap * 2 + item) + np.sqrt(cap + item))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio ** 1.2)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2.5)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 1.01
        if (cap + item) % 4 == 0:
            priorities[i] *= 0.95
    return priorities
